import{_ as n,r as o,o as s,c,a as e,b as r,e as i}from"./app.547295de.js";const _={},h=i(`<p align="center"><a href="https://github.com/wochenlong/lora-scripts-next" style="margin:2px;"><img alt="GitHub Repo stars" src="https://img.shields.io/github/stars/wochenlong/lora-scripts-next"></a><a href="https://github.com/wochenlong/lora-scripts-next" style="margin:2px;"><img alt="GitHub forks" src="https://img.shields.io/github/forks/wochenlong/lora-scripts-next"></a><a href="https://raw.githubusercontent.com/wochenlong/lora-scripts-next/master/LICENSE" style="margin:2px;"><img src="https://img.shields.io/github/license/wochenlong/lora-scripts-next" alt="license"></a><a href="https://github.com/wochenlong/lora-scripts-next/releases" style="margin:2px;"><img src="https://img.shields.io/github/v/release/wochenlong/lora-scripts-next?color=blueviolet&amp;include_prereleases" alt="release"></a></p><h3 id="版本记录" tabindex="-1"><a class="header-anchor" href="#版本记录" aria-hidden="true">#</a> 版本记录</h3><h4 id="v2-5-0" tabindex="-1"><a class="header-anchor" href="#v2-5-0" aria-hidden="true">#</a> v2.5.0</h4><ul><li>UI 焕新：侧栏导航重构，训练 / 工具 / 帮助分区清晰</li><li>首页传送门：卡片式入口快速跳转训练、监控、新手上路</li><li>训练监控仪表盘：GPU 实时指标（型号、负载、显存、温度、功耗）、总步数、训练参数速查</li><li>新手上路页面：帮助新用户快速了解训练流程</li><li>训练监控前后端分离为独立 train_monitor/ 模块</li><li>CSS 去重清理（~1660 行冗余代码）</li></ul><h4 id="v2-4-0" tabindex="-1"><a class="header-anchor" href="#v2-4-0" aria-hidden="true">#</a> v2.4.0</h4><ul><li>训练子进程环境隔离，防止系统 site-packages 污染</li><li>NaN 值自动过滤，修复 LyCORIS 训练崩溃</li><li>采样保护：无 sample_prompts 时自动移除采样参数</li><li>attn_mode 自动降级：xformers/flash 未安装时降级到可用方案</li><li>路径规范化：自动将 \\ 转为 /</li><li>整合包 tkinter 支持，修复文件夹选择器</li><li>install_xformers.bat 一键安装</li></ul><h4 id="v2-3-0" tabindex="-1"><a class="header-anchor" href="#v2-3-0" aria-hidden="true">#</a> v2.3.0</h4><ul><li>TensorBoard 同源 Loss 曲线，默认四宫格（loss/average、loss/current、loss/epoch_average、lr/unet）</li><li>曲线交互优化：视野按钮替代滑动条</li><li>训练参数速查卡片（学习率、优化器、总步数等）</li><li>终端日志同步到监控页</li><li>端口冲突自动回退</li></ul><h4 id="v2-1-0" tabindex="-1"><a class="header-anchor" href="#v2-1-0" aria-hidden="true">#</a> v2.1.0</h4><ul><li>Flash Attention 2 预构建 Wheel 支持 Windows（无需 C++ 编译器）</li><li>新增按步数保存模型选项</li><li>修复 LoKr conv_dim/conv_alpha 显示为 undefined 的问题</li><li>修复跨盘符 output_dir 导致监控页面断联的问题</li><li>新增 triton-windows 依赖自动安装</li></ul><h4 id="v2-0-0" tabindex="-1"><a class="header-anchor" href="#v2-0-0" aria-hidden="true">#</a> v2.0.0</h4><ul><li>Windows 便携包发布，双击即用</li><li>Flash Attention 2 自动加速（自动检测并启用）</li><li>AMD GPU 检测与友好提示</li><li>自动 bf16/fp16 修复</li><li>--browser chrome/edge 浏览器选择</li><li>更新检查功能</li></ul><h4 id="v1-next" tabindex="-1"><a class="header-anchor" href="#v1-next" aria-hidden="true">#</a> 基于原版的改进</h4><ul><li>Anima 训练支持（LoRA / LoKr / T-LoRA）</li><li>T-LoRA 支持（Timestep-Dependent LoRA）</li><li>交互式 Loss 曲线图（ECharts 缩放/平移）</li><li>实时训练监控页面（端口 6008）</li><li>Anima 后端迁移至 kohya-ss/sd-scripts</li><li>AutoDL 专用启动脚本</li></ul><h3 id="原版更新日志" tabindex="-1"><a class="header-anchor" href="#原版更新日志" aria-hidden="true">#</a> 原版更新日志</h3><p>本项目 Fork 自 <a href="https://github.com/Akegarasu/lora-scripts" target="_blank" rel="noopener noreferrer">Akegarasu/lora-scripts</a>，原版更新日志请参见原仓库。</p>`);function u(g,p){return s(),c("div",null,[e("h2",{id:"\u66F4\u65B0\u65E5\u5FD7",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#\u66F4\u65B0\u65E5\u5FD7","aria-hidden":"true"},"#"),r(" \u66F4\u65B0\u65E5\u5FD7")],-1),h])}var x=n(_,[["render",u],["__file","changelog.html.vue"]]);export{x as default};